-- cross-module planning/vocabulary advice is reachable for any module weakness.

BEGIN;

INSERT INTO public.learning_resources
  (module, level, topic, language, resource_type, is_active, title, description, body)
VALUES
  ( 'sprechen', 'a1', 'dialoge', 'ru', 'advice', true,
    'Как отвечать на вопросы экзаменатора без долгих пауз',
    'Базовые ответы (имя, профессия, хобби) надо довести до автоматизма — паузы убивают баллы за беглость.',
    $body${"why":"На A1 паузы при ответе на простые вопросы — не признак того, что вы плохо знаете язык. Это признак того, что в голове ещё нет автоматизированных шаблонов, и мозг каждый раз строит фразу с нуля: подбирает слово, вспоминает род, спрягает глагол. На экзамене стресс умножает это в три раза. Решение — не «учить больше слов», а довести базовые ответы до автоматизма.","steps":["Выпишите ответы на 5 обязательных вопросов первой части Sprechen: имя, возраст, страна, место жительства, профессия, языки, хобби. По 1-2 коротких предложения на каждый.","Заучите эти ответы вслух, не в голове. Минимум 10 повторений в день в течение 3 дней. Цель — чтобы фраза «Ich heiße Anna, ich komme aus Russland, ich wohne jetzt in Berlin» звучала автоматически.","На 4-й день запишите себя на диктофон телефона, отвечая на каждый вопрос. Прослушайте — сравните с тем, как звучите вы и как звучат немцы в учебных видео.","Меняйте порядок ответов и формулировки. Если выучили только один вариант — на экзамене сломаетесь, если экзаменатор спросит чуть иначе."],"drill":"Прямо сейчас, не вставая: ответьте вслух на «Wie heißen Sie? Woher kommen Sie? Was machen Sie beruflich?». Засеките паузы. Если пауза дольше 2 секунд хотя бы на одном вопросе — это и есть ваша точка приложения усилий на ближайшую неделю.","avoid":"Не заучивайте сложные «красивые» конструкции типа «Ich interessiere mich besonders für…» — на A1 экзаменатор их не ждёт и они звучат заученно. Простые предложения, сказанные уверенно, дают больше баллов, чем сложные с паузами.","progress":"Через 5-7 дней ответ на любой из 5 базовых вопросов идёт за 1-2 секунды раздумий. Если приходится «вспоминать» — продолжайте drill ещё неделю."}$body$::jsonb ),
  ( 'sprechen', 'a1', 'aussprache', 'ru', 'advice', true,
    'Произношение трёх звуков, по которым вас сразу узнают как русского',
    'Звуки ü, ö, ch — главные маркеры акцента на A1. Их можно поставить за неделю целенаправленной тренировки.',
    $body${"why":"На A1 экзаменатор не ждёт идеального произношения, но три звука — ü, ö и ch — настолько отличают носителя от изучающего, что без них речь звучит «по-русски». Хорошая новость: эти звуки физически выполнимы, нужна только мышечная привычка губ и языка. Плохая — без зеркала и записи себя их не поставить.","steps":["ü: скажите русское «и», зафиксируйте язык, теперь сложите губы как для «у». Звук должен идти из передней части рта. Тренируйте на словах: über, München, fünf, Tür, müde.","ö: скажите «э», зафиксируйте, округлите губы как для «о». Слова: schön, hören, möchte, Köln, zwölf.","ch (мягкое): после i, e, ö, ü — это не русское «х», а звук как при шипении на кота. Слова: ich, mich, nicht, Mädchen, München.","Записывайте себя каждый день. Слушайте — отличие свой/немецкий заметно сразу. Не пытайтесь «думать о звуках» — тренируйте механически по 5 минут в день."],"drill":"Произнесите вслух 5 раз: «Ich möchte fünf Bücher über München lesen». Если хоть один звук «съедается» в русское «и/о/х» — это рабочая фраза для тренировки на неделю.","avoid":"Не заменяйте ü на «у» и ö на «о» — это самая частая ошибка. Лучше произнести с напряжённой артикуляцией («слишком немецкое» ü), чем сглаженно — экзаменатор оценит усилие.","progress":"Через неделю при записи себя на диктофон вы слышите ясное различие между ich и «ищ», между schön и «шон». Если различия нет — ставьте звуки с преподавателем-фонетистом, самостоятельно дальше не пробьётесь."}$body$::jsonb ),
  ( 'sprechen', 'a1', 'wortschatz', 'ru', 'advice', true,
    '200 слов, которые покрывают 80% разговоров на A1',
    'Не учите весь Wortliste Goethe — выделите ядро из 200 слов и доведите его до автоматизма.',
    $body${"why":"Официальный Wortliste Goethe A1 содержит около 650 слов. Выучить все за 2-3 месяца до экзамена нереально, и не нужно. Анализ реальных экзаменов показывает: ~200 базовых слов покрывают подавляющее большинство ситуаций Sprechen и Schreiben. Лучше знать 200 слов «намертво» — с правильным родом, множественным числом, базовым употреблением — чем 600 «примерно».","steps":["Сосредоточьтесь на 6 темах: семья, работа/учёба, дом и быт, еда, погода и время, базовые действия (gehen, kommen, machen, haben, sein, kaufen, essen).","Каждое существительное учите с артиклем и формой множественного: не «Tisch», а «der Tisch — die Tische». Без рода слово бесполезно для предложений.","Учите слова в коротких фразах, а не списками. Не «kaufen — покупать», а «Ich kaufe Brot im Supermarkt». Так слово закрепляется в контексте.","Каждый день 15 минут — повторение карточками (Anki, Quizlet или просто бумажные). Новые слова — только после того, как старые идут без задержки."],"drill":"Откройте холодильник или оглядите комнату. Назовите вслух 10 предметов с артиклем: «der Stuhl, das Fenster, die Lampe…». Если на каком-то затруднились — это слово в зону повторения на завтра.","avoid":"Не учите редкие слова из учебников «для уровня A1» вроде der Schornsteinfeger или die Litfaßsäule. На экзамене они не встретятся, а место в памяти займут.","progress":"Через 3 недели вы можете без подготовки 1 минуту описывать свою комнату/квартиру/семью, не делая больше 1-2 пауз для подбора слова."}$body$::jsonb ),
  ( 'sprechen', 'a1', 'briefe', 'ru', 'advice', true,
    'Как сформулировать просьбу в Sprechen Teil 3 без долгих фраз',
    'Третья часть Sprechen — короткая просьба партнёру. Достаточно 1-2 предложений по шаблону.',
    $body${"why":"В Sprechen Teil 3 на A1 нужно сформулировать просьбу по карточке (например: «Stift» — попросите ручку). Многие кандидаты пытаются построить сложную фразу типа «Könntest du mir vielleicht deinen Stift für einen Moment geben?», запутываются и теряют баллы. На A1 экзаменатор ждёт простоты: одно понятное предложение с просьбой.","steps":["Запомните 3 рабочих шаблона: «Hast du einen Stift?» (есть ли у тебя X?), «Kannst du mir bitte einen Stift geben?» (можешь ли мне дать?), «Ich brauche einen Stift, bitte.» (мне нужен X).","Тренируйтесь на 10 типичных предметах: Stift, Buch, Wasser, Hilfe, Adresse, Telefonnummer, Zeit, Brille, Geld, Schlüssel.","Произнесите фразу с дружелюбной интонацией — тон важнее идеальной грамматики. «Bitte» в конце почти всегда уместно.","Если экзаменатор отвечает встречно — не паникуйте. Достаточно «Danke schön!» или «Vielen Dank!». Не нужно длинных ответов."],"drill":"Возьмите 5 предметов из своей комнаты. Для каждого вслух сформулируйте просьбу по шаблону «Kannst du mir bitte X geben?». На третьем-четвёртом предмете должно идти автоматически.","avoid":"Не используйте Konjunktiv II («Könntest du…», «Würden Sie…») на A1 — это уровень B1. Простой Präsens с «bitte» — норма для вашего уровня.","progress":"Через 3-4 дня тренировок вы можете сформулировать просьбу о любом предмете быта без раздумий, в одном коротком предложении."}$body$::jsonb ),
  ( 'sprechen', 'a1', 'modal-verben', 'ru', 'advice', true,
    'Модальные глаголы в речи: кратко, к месту, без ошибок',
    'На A1 нужны 4 модальных: können, müssen, möchten, wollen. Главная проблема — порядок слов.',
    $body${"why":"Модальные глаголы — самая частая ошибка в устной речи на A1. Не потому, что их сложно спрягать (это просто), а потому, что в немецком инфинитив второго глагола уезжает в конец предложения: «Ich muss morgen früh aufstehen». Русскоязычные кандидаты по инерции говорят «Ich muss aufstehen morgen früh» — экзаменатор сразу слышит ошибку.","steps":["Выучите 4 модальных в Präsens для ich/du/er: ich kann/du kannst/er kann; ich muss/du musst/er muss; ich möchte/du möchtest/er möchte; ich will/du willst/er will.","Запомните железное правило: модальный — на 2-м месте, инфинитив — в самом конце. «Ich kann gut Deutsch sprechen», а не «Ich kann sprechen gut Deutsch».","Тренируйте 10 типичных фраз: «Ich kann Auto fahren», «Ich muss heute arbeiten», «Ich möchte einen Kaffee bestellen», «Ich will nach Berlin fliegen».","Различайте möchten (вежливое «хотел бы») и wollen (категоричное «хочу»). На A1 в большинстве случаев нужен möchten — он мягче и уместнее в общении."],"drill":"Составьте вслух 5 предложений о завтрашнем дне с модальными: «Morgen muss ich…», «Morgen möchte ich…», «Morgen kann ich…». Следите, чтобы инфинитив был в конце.","avoid":"Не говорите «Ich will» вместо «Ich möchte», когда что-то заказываете в кафе или просите в магазине. «Ich will einen Kaffee» звучит грубо — носители используют «Ich möchte einen Kaffee, bitte».","progress":"Через неделю в спонтанной речи модальные с инфинитивом в конце идут автоматически. Если ловите себя на ошибке порядка слов — продолжайте drill каждый день по 5 минут."}$body$::jsonb ),
  ( 'sprechen', 'a1', 'perfekt', 'ru', 'advice', true,
    'Как рассказать о вчерашнем дне в Perfekt без ошибок',
    'Главное — выучить 30 «правильных» Partizip II ходовых глаголов и не путать haben/sein.',
    $body${"why":"На A1 в устной речи прошедшее время — это всегда Perfekt (Präteritum только для war, hatte). Проблема в том, что нужно одновременно: 1) выбрать вспомогательный глагол haben или sein, 2) поставить его на 2-е место и спрягать, 3) поставить Partizip II в конец, 4) знать форму этого Partizip. Четыре операции одновременно — мозг A1 не справляется без подготовки.","steps":["Выучите наизусть Partizip II 30 самых частых глаголов: gemacht, gegessen, getrunken, gefahren, gegangen, gewesen, gehabt, gekauft, gelernt, gearbeitet, gesehen, geschlafen, gesprochen, gelesen, geschrieben и т.д.","Запомните железные группы для sein: глаголы движения (gehen, fahren, kommen, fliegen) и изменения состояния (aufstehen, einschlafen). Плюс sein и bleiben. Всё остальное — haben.","Тренируйте по шаблону «Gestern habe/bin ich [Partizip II в конце]»: «Gestern habe ich gearbeitet», «Gestern bin ich nach Berlin gefahren».","Расскажите вслух о своём вчерашнем дне в 5-7 предложениях. Записывайте на диктофон — потом сравните с правильными формами."],"drill":"Прямо сейчас вслух: расскажите 3 предложения о том, что делали вчера утром. Если на каком-то спотыкаетесь на форме Partizip — выпишите этот глагол на карточку.","avoid":"Не используйте Präteritum (machte, ging, kaufte) в устной речи на A1 — в Германии это книжная форма, в разговоре звучит странно. Исключение: war и hatte — их Präteritum как раз нормально.","progress":"Через неделю описание вчерашнего дня в 5-7 предложениях идёт без долгих пауз и с правильным выбором haben/sein."}$body$::jsonb ),
  ( 'sprechen', 'a1', 'dialoge', 'ru', 'advice', true,
    'Что делать, если вы не поняли вопрос экзаменатора',
    'На A1 это нормально — главное, не молчать. Используйте 3 фразы для переспроса.',
    $body${"why":"Молчание после вопроса экзаменатора — самая дорогая ошибка на устной части A1. Экзаменатор не сможет оценить то, чего вы не сказали. При этом просьба переспросить или объяснить слово не снижает балл — наоборот, показывает коммуникативную компетенцию. Главное — не молчать и не отвечать невпопад.","steps":["Выучите 3 рабочие фразы переспроса: «Entschuldigung, können Sie das wiederholen?» (можете повторить?), «Entschuldigung, was bedeutet …?» (что значит …?), «Ich habe das nicht verstanden» (я не понял).","Тренируйте их так, чтобы они выскакивали автоматически — за полсекунды после момента непонимания. Если думать «как же сказать переспросить» — тоже потеряете время.","Если не знаете слово — описывайте: «Wie sagt man auf Deutsch das Ding zum Schreiben?» (как сказать «вещь для письма»?). Это нормальная коммуникативная стратегия.","Если совсем не поняли — честно скажите «Ich verstehe leider nicht. Können Sie es einfacher sagen?» Экзаменатор переформулирует."],"drill":"Прямо сейчас представьте, что не поняли вопрос. Произнесите вслух 3 раза каждую из трёх фраз переспроса. Они должны звучать естественно, без запинок.","avoid":"Не угадывайте ответ, если не поняли вопрос. Ответ невпопад показывает экзаменатору, что вы не понимаете немецкий, — это хуже, чем честное «не понял, повторите».","progress":"К моменту экзамена вы можете без задержки попросить повторить вопрос или объяснить слово, не теряя нити разговора."}$body$::jsonb ),
  ( 'schreiben', 'a1', 'briefe', 'ru', 'advice', true,
    'Структура письма A1: 6 обязательных элементов',
    'Без обращения, прощания и подписи письмо не оценивается — даже идеально написанное.',
    $body${"why":"В Schreiben A1 баллы по критерию «коммуникативное оформление» вы получаете не за богатство языка, а за наличие структурных элементов. Письмо без обращения или без прощания экзаменатор оценивает как «Form nicht erfüllt» — даже если содержание идеальное. Каркас важнее языкового мастерства.","steps":["Запомните 6 обязательных элементов: 1) дата (необязательна, но желательна), 2) обращение «Liebe/r [имя],» (с запятой!), 3) вступительная фраза, 4) основной текст с покрытием 3 пунктов задания, 5) прощание «Liebe Grüße» / «Viele Grüße», 6) ваше имя.","После «Liebe/r Name,» идёт пустая строка и текст с маленькой буквы (это не ошибка, это норма!): «Liebe Anna, // ich schreibe dir, weil…»","Каждый из 3 пунктов задания — минимум 1 полное предложение. Не объединяйте 2 пункта в одну фразу — экзаменатор может не засчитать один из них.","Перед сдачей перечитайте: все 3 пункта закрыты? Обращение и прощание есть? Подпись есть?"],"drill":"Возьмите любое задание Schreiben A1 (есть в Modellsatz Goethe). Не пишите само письмо — нарисуйте только скелет: «Liebe X, [пункт 1: …], [пункт 2: …], [пункт 3: …], Liebe Grüße, [имя]». Это упражнение за 2 минуты.","avoid":"Не начинайте письмо с «Hallo!» — для уровня A1 безопаснее «Liebe/r…». «Hallo» допустимо, но менее формально и в письмах учебного типа считается слабее.","progress":"После 5 написанных писем структура выходит автоматически — садитесь и сразу пишете «Liebe…», не задумываясь над каркасом."}$body$::jsonb ),
  ( 'schreiben', 'a1', 'inhaltspunkte', 'ru', 'advice', true,
    'Как покрыть все 3 пункта задания и не потерять ни одного',
    'Главная причина потери баллов — забыть один из пунктов. Простой приём — отметить их перед написанием.',
    $body${"why":"По критерию «Inhalt» (содержание) на A1 вы получаете полный балл, только если раскрыли все 3 пункта задания. Если забыли хотя бы один — балл сразу снижается на треть. При этом сам по себе пропуск пункта — не от незнания языка, а от спешки и стресса. Это самая обидная потеря баллов.","steps":["Перед началом письма прочитайте задание дважды и подчеркните 3 пункта. Если задание на бумаге — поставьте рядом галочки/нумерацию.","Под черновиком выпишите 3 ключевых слова — по одному на каждый пункт. Это ваш чеклист.","Пишите письмо, периодически смотря на чеклист. После каждого пункта — вычеркните.","Перед сдачей сверьтесь с чеклистом ещё раз. Если какой-то пункт раскрыт одной фразой типа «Ja, gerne!» — добавьте 1-2 предложения с деталью."],"drill":"Возьмите любое задание Schreiben A1. Не пишите письмо — за 30 секунд выпишите 3 ключевых слова для каждого пункта. Это та операция, которая на экзамене занимает 1 минуту, но спасает от потери баллов.","avoid":"Не объединяйте 2 пункта в одно предложение типа «Ja, ich komme um 18 Uhr und bringe Wein mit». Экзаменатор может засчитать только один пункт. Лучше 2 коротких предложения.","progress":"После 5-7 тренировочных писем вы автоматически выписываете чеклист и не сдаёте письмо без проверки. Пропуск пункта на экзамене становится практически невозможным."}$body$::jsonb ),
  ( 'schreiben', 'a1', 'modal-verben', 'ru', 'advice', true,
    'Модальные в письме: как использовать без ошибок порядка слов',
    'Для писем достаточно 3 модальных: möchten, können, müssen. Главное — инфинитив в конце.',
    $body${"why":"В Schreiben A1 модальные глаголы — самый удобный способ сделать текст разнообразным. Вместо плоских «Ich komme», «Ich bringe» можно «Ich möchte kommen», «Ich kann mitbringen», «Ich muss arbeiten». Но порядок слов с модальным — главный камень преткновения: инфинитив должен быть в самом конце предложения.","steps":["Запомните 3 рабочих модальных для писем: möchten (вежливое «хотел бы»), können (могу/возможно), müssen (должен/нужно).","Железное правило: «модальный на 2-м месте + инфинитив в самом конце». «Ich möchte am Samstag zu deiner Party kommen», а не «Ich möchte kommen am Samstag zu deiner Party».","Используйте möchten для вежливых формулировок — это уровень A1+ и сразу показывает экзаменатору, что вы знаете больше, чем просто Präsens.","В отрицании — nicht ставится перед инфинитивом: «Ich kann am Samstag leider nicht kommen»."],"drill":"Напишите 3 предложения о ваших планах на следующую неделю — каждое с модальным глаголом и инфинитивом в конце. Перечитайте — инфинитив везде в самом конце?","avoid":"Не используйте «wollen» в письмах учебного формата (приглашение, ответ другу) — звучит грубо. «Möchten» мягче и уместнее в большинстве ситуаций.","progress":"В написанных письмах все предложения с модальными имеют правильный порядок слов. Если ловите ошибку порядка — выпишите 5 типичных предложений и переписывайте каждое утро в течение 3 дней."}$body$::jsonb ),
  ( 'schreiben', 'a1', 'perfekt', 'ru', 'advice', true,
    'Perfekt в письме: как рассказать о прошлом без путаницы haben/sein',
    'В письме часто нужно рассказать, что вы сделали. Главная проблема — выбор вспомогательного глагола.',
    $body${"why":"В Schreiben A1 Perfekt появляется почти в каждом задании: «расскажи, как прошёл твой день», «извинись, что не пришёл вчера», «опиши свою поездку». Ошибки в Perfekt типа «Ich habe nach Berlin gefahren» вместо «Ich bin nach Berlin gefahren» — самая массовая категория ошибок на A1.","steps":["Запомните железное правило: с sein идут глаголы движения (gehen, kommen, fahren, fliegen, laufen) и изменения состояния (aufstehen, einschlafen, sterben, wachsen). Плюс sein и bleiben. Всё остальное — с haben.","Выучите наизусть Partizip II 30 ходовых глаголов: gewesen, gehabt, gemacht, gegessen, getrunken, gefahren, gegangen, gekauft, gesehen, geschlafen, gearbeitet, gelernt, gesprochen, gelesen, geschrieben, gekommen, gegangen, gefahren.","Структура: вспомогательный глагол на 2-м месте, Partizip II в конце. «Ich habe gestern einen Brief geschrieben», а не «Ich habe geschrieben einen Brief gestern».","Перед сдачей письма проверьте каждый Perfekt: правильный ли вспомогательный? Правильная ли форма Partizip? Стоит ли Partizip в конце?"],"drill":"Напишите 5 предложений о том, что делали в прошлые выходные. Каждое — в Perfekt. Проверьте: где haben, где sein, и стоит ли Partizip в конце.","avoid":"Не пишите «Ich habe nach Hause gegangen» — это самая частая ошибка. Gehen всегда с sein: «Ich bin nach Hause gegangen». То же самое с fahren, kommen, fliegen.","progress":"В черновиках писем вы перестаёте задумываться над выбором haben/sein — рука пишет правильно автоматически."}$body$::jsonb ),
  ( 'schreiben', 'a1', 'prapositionen', 'ru', 'advice', true,
    'Предлоги места: in, an, auf — как не перепутать',
    'Три самых частых предлога места на A1. Логика выбора простая, если понять принцип.',
    $body${"why":"На A1 в письмах постоянно нужно описывать, где вы находитесь или куда идёте. «Ich bin in/an/auf …» — без предлога места предложение нельзя построить, и выбор не такой очевидный, как кажется. Русский язык даёт здесь ложные подсказки: мы говорим «на работе», немцы — «in der Arbeit» или «bei der Arbeit», но не «auf der Arbeit».","steps":["in — внутри замкнутого пространства: in der Schule, in der Stadt, in dem Haus, in Berlin, in Deutschland.","an — у/около вертикальной поверхности или края: an der Wand, an der Tür, an dem See (на берегу озера), an dem Bahnhof.","auf — на горизонтальной поверхности или площадке: auf dem Tisch, auf dem Boden, auf dem Markt, auf der Straße, auf dem Spielplatz.","Запомните типичные коллокации, которые не выводятся логикой: ins Kino gehen, in die Schule gehen, auf die Party gehen, zum Arzt gehen (с zu)."],"drill":"Опишите вслух 5 мест, где вы были вчера: «Ich war in/an/auf …». Проверьте по правилам выше — правильный ли предлог?","avoid":"Не используйте «auf» по русской аналогии «на работе» — в немецком работа это «bei der Arbeit» или «in der Arbeit». «Auf der Arbeit» допустимо в разговорной речи, но в письме лучше избежать.","progress":"После 10-15 написанных предложений с предлогами места выбор in/an/auf идёт автоматически в типичных ситуациях."}$body$::jsonb ),
  ( 'schreiben', 'a1', 'cases', 'ru', 'advice', true,
    'Nominativ и Akkusativ: как не перепутать «кто» и «что»',
    'На A1 нужны только два падежа. Главное правило — артикль меняется только в Akkusativ для мужского рода.',
    $body${"why":"На A1 для письма достаточно двух падежей: Nominativ (подлежащее, «кто/что») и Akkusativ (прямое дополнение, «кого/что»). Хорошая новость: артикли меняются только для мужского рода (der → den, ein → einen). Для женского, среднего и множественного — всё остаётся как в Nominativ. Это правило можно выучить за 10 минут.","steps":["Nominativ — подлежащее: der Mann, die Frau, das Kind, die Kinder. То, кто/что выполняет действие: «Der Mann liest».","Akkusativ — прямое дополнение: den Mann, die Frau, das Kind, die Kinder. То, на что направлено действие: «Ich sehe den Mann».","Запомните: меняется только мужской род. der → den, ein → einen, mein → meinen, kein → keinen.","Запомните глаголы, которые всегда требуют Akkusativ: haben, sehen, kaufen, essen, trinken, brauchen, möchten, lesen, schreiben."],"drill":"Составьте 5 предложений с глаголом haben или sehen + существительным мужского рода: «Ich habe einen Bruder», «Ich sehe den Hund». Проверьте: артикль в Akkusativ изменился?","avoid":"Не путайте Nominativ и Akkusativ для женского/среднего рода — они одинаковые! «Die Frau ist nett» (Nominativ), «Ich sehe die Frau» (Akkusativ) — артикль один и тот же. Не пытайтесь искать там разницу.","progress":"В письме все артикли при мужском роде после haben/sehen/kaufen/möchten автоматически в Akkusativ. Проверка перед сдачей занимает 30 секунд."}$body$::jsonb ),
  ( 'lesen', 'a1', 'texts-reading', 'ru', 'advice', true,
    'Как искать ответы в коротких текстах: не читайте весь текст',
    'Lesen на A1 — это не про чтение целиком, а про быстрый поиск нужной информации.',
    $body${"why":"На A1 Lesen времени в обрез: 25 минут на 3-4 задания. Кандидаты, которые читают каждый текст полностью, не успевают. Хитрость в том, что задания на A1 спроектированы так, что ответ можно найти, просканировав текст по ключевым словам. Полностью читать не нужно — нужно научиться сканировать.","steps":["Сначала прочитайте вопрос и варианты ответа. Подчеркните ключевое слово в вопросе (имя, дата, тема, действие).","Сканируйте текст глазами — ищите это ключевое слово или его синоним. Не читайте слева направо, а «прыгайте» взглядом.","Когда нашли ключевое слово — прочитайте только то предложение, в котором оно стоит, и одно предложение до и после.","Только потом выбирайте вариант ответа. Если сомневаетесь — переходите к следующему заданию, вернётесь, если останется время."],"drill":"Возьмите любой текст Lesen A1 из Modellsatz Goethe. Засеките 30 секунд. Найдите в тексте ответ на один вопрос — но не читая весь текст, а только сканируя по ключевому слову.","avoid":"Не пытайтесь понять каждое слово в тексте — на A1 это убийца времени. Незнакомое слово, которое не нужно для ответа на вопрос, — пропускайте без сожалений.","progress":"После 5-7 тренировочных Lesen A1 вы укладываетесь в 25 минут на все задания и остаётся 3-5 минут на проверку."}$body$::jsonb ),
  ( 'lesen', 'a1', 'wortschatz', 'ru', 'advice', true,
    'Что делать с незнакомыми словами в тексте: 3 стратегии',
    'Не паникуйте от незнакомых слов — большинство можно понять из контекста или вообще пропустить.',
    $body${"why":"На A1 в текстах Lesen встречаются слова, которых нет в Wortliste — это сделано специально, чтобы проверить, как вы справляетесь с непониманием. Кандидаты, которые впадают в ступор от каждого незнакомого слова, теряют время и заваливают модуль. Кандидаты, которые умеют пропускать или угадывать, — справляются.","steps":["Стратегия 1: пропустить. Если слово не в той фразе, где находится ответ на вопрос, — игнорируйте. Большинство незнакомых слов на A1 в задание не входят.","Стратегия 2: угадать по контексту. «Ich kaufe einen Birnsaft» — даже не зная Birnsaft, вы понимаете «покупаю какой-то сок».","Стратегия 3: распознать по корню. Многие сложные слова — это комбинации простых. «Stadtbibliothek» = Stadt (город) + Bibliothek (библиотека) = «городская библиотека».","Если слово принципиально для ответа и совсем непонятно — выбирайте ответ, который кажется наиболее логичным, и идите дальше."],"drill":"Возьмите текст Lesen A1. Найдите 5 слов, которых не знаете. Для каждого решите за 5 секунд: пропустить / угадать / разобрать по корням. Запишите догадку. Потом проверьте по словарю — насколько часто оказались правы.","avoid":"Не пытайтесь переводить каждое незнакомое слово в голове на русский. Это блокирует понимание. Лучше работайте с целыми фразами: «эта фраза примерно про то, что…».","progress":"После 10 тренировочных текстов вы перестаёте паниковать от незнакомых слов и автоматически выбираете одну из 3 стратегий."}$body$::jsonb ),
  ( 'horen', 'a1', 'audio-listening', 'ru', 'advice', true,
    'Как слушать объявления и короткие диалоги: ловите ключевые слова',
    'На A1 в Hören не нужно понимать каждое слово — нужно поймать 2-3 ключевых.',
    $body${"why":"Hören A1 пугает кандидатов больше всего — кажется, что носители говорят слишком быстро. На самом деле задания спроектированы так, что для правильного ответа достаточно поймать 2-3 ключевых слова: цифру, имя, время, место. Если слушать «всё», мозг перегружается и пропускает даже эти ключевые слова.","steps":["Перед прослушиванием прочитайте вопрос и варианты ответа. Подчеркните, какую информацию нужно поймать: время? цена? адрес? имя?","Во время прослушивания сосредоточьтесь только на этой информации. Всё остальное пусть «проходит мимо».","На A1 каждое аудио играют дважды — это правило экзамена. На первом прослушивании ловите общую идею, на втором — конкретное слово для ответа.","Если пропустили ответ на первом прослушивании, не думайте о нём во время второго — иначе пропустите ещё."],"drill":"Возьмите любое аудио Hören A1 (есть в Modellsatz Goethe). Перед запуском подчеркните в вопросе, что нужно поймать. После прослушивания оцените: уловили нужную информацию или слушали «всё подряд»?","avoid":"Не пытайтесь параллельно «переводить» услышанное на русский — это занимает мозг и вы пропускаете следующее предложение. Слушайте сразу на немецком, целыми фразами.","progress":"После 10 тренировочных аудио вы автоматически фокусируетесь на ключевой информации и игнорируете «шум». Понимание целевых слов — 80%+."}$body$::jsonb ),
  ( 'horen', 'a1', 'dialoge', 'ru', 'advice', true,
    'Как тренировать ухо к разговорной немецкой речи',
    'Учебные аудио и реальная речь — разные миры. Нужно слушать оба, но реальную — больше.',
    $body${"why":"На A1 экзамене аудио записаны актёрами, которые произносят слова чётко и медленно. Но если вы тренировались только на учебных материалах, а реальную немецкую речь не слышали — на экзамене Teil 4 (где интонации более естественные) вы провалитесь. Ухо нужно тренировать к разговорному темпу заранее.","steps":["10 минут в день слушайте короткие диалоги учебного формата (Goethe, DW Nicos Weg, Hueber Schritte) — это базовый навык для Teil 1-3.","Параллельно 5-10 минут в день слушайте Easy German (на YouTube) — реальные интервью с субтитрами на немецком и английском. Это тренирует ухо к естественному темпу.","Прослушивайте одно и то же аудио 2-3 раза: первый раз — общая идея, второй — детали, третий — со скриптом перед глазами для проверки.","Через 2 недели попробуйте слушать без скрипта аудио, которые раньше слышали со скриптом. Понимание должно улучшиться кратно."],"drill":"Прямо сейчас откройте любое короткое видео Easy German (1-2 минуты). Слушайте без субтитров. После — пересмотрите с субтитрами. Сколько процентов вы поняли с первого раза?","avoid":"Не слушайте только официальные учебные аудио — на экзамене аудио чуть быстрее, чем в учебниках. Реальная немецкая речь должна составлять минимум 30% вашей тренировки на слух.","progress":"Через 3 недели регулярного слушания вы понимаете 70%+ простого диалога на улице (Easy German) без субтитров."}$body$::jsonb ),
  ( 'horen', 'a1', 'audio-listening', 'ru', 'advice', true,
    'Что делать, если пропустили ответ на первом прослушивании',
    'Не паниковать. Второе прослушивание — ваш реальный шанс. Главное — не залипнуть.',
    $body${"why":"На A1 аудио в Hören Teil 1-2 играют дважды (правило экзамена). Самая распространённая ошибка — пропустив ответ на первом прослушивании, кандидат начинает мысленно «вспоминать», что было сказано, и пропускает уже второй фрагмент. В итоге теряет два балла вместо одного.","steps":["Если на первом прослушивании пропустили ответ — поставьте на этом задании знак вопроса в черновике и СРАЗУ слушайте следующее задание.","На втором прослушивании тоже целенаправленно слушайте именно ту фразу, которую пропустили. Подготовка к этому моменту — ваш единственный шанс.","Если и на втором не уловили — выберите ответ интуитивно. Пустой ответ = 0 баллов. Угадывание из 3 вариантов = 33% шанс получить балл.","Не нервничайте видимо — стресс физически блокирует слух. Глубокий вдох-выдох между заданиями возвращает концентрацию."],"drill":"Возьмите тренировочное Hören A1 Teil 1. На первом прослушивании специально отвлекитесь на одном задании. Затем тренируйтесь сосредоточиться именно на этом задании на втором прослушивании.","avoid":"Не оставляйте вопрос без ответа, даже если совсем не уловили. На A1 нет штрафов за неправильный ответ — только баллы за правильный. Угадывайте.","progress":"После 5-7 тренировок вы научились мгновенно переключаться на следующее задание после пропуска и эффективно использовать второе прослушивание."}$body$::jsonb ),
  ( 'lesen', 'a1', 'audio-listening', 'ru', 'advice', true,
    'Как тренировать чтение на слух одновременно',
    'Совместная тренировка чтения и слуха ускоряет прогресс в обоих модулях.',
    $body${"why":"Чтение и слух тренируются эффективнее вместе, чем по отдельности. Когда вы видите текст и одновременно слышите его произнесённым — мозг связывает написанное слово с его звучанием. Это ускоряет распознавание слов в обоих модулях. Этот приём называется shadowing и в методике немецкого считается одним из самых эффективных для A1.","steps":["Найдите аудио + транскрипт одного и того же текста (DW Nicos Weg, любые учебные материалы Goethe).","Первый проход: слушайте без текста. Оцените, сколько поняли.","Второй проход: слушайте с текстом перед глазами, читайте параллельно. Отмечайте слова, которые в тексте видите чётко, а на слух не узнаёте.","Третий проход: слушайте без текста снова. Понимание должно вырасти кратно."],"drill":"Возьмите любой текст из DW Nicos Weg A1 со встроенным аудио. Сделайте 3-проходное упражнение выше за 10 минут. На третьем прослушивании понимание должно быть выше, чем на первом.","avoid":"Не читайте только глазами без озвучки — мозг запоминает слово как «картинку», а на экзамене вам нужна связь буква-звук. Тексты без аудио — менее эффективны для A1.","progress":"Через 2 недели регулярных shadowing-упражнений вы узнаёте на слух 70%+ слов из своей лексики A1, которые раньше понимали только в письме."}$body$::jsonb ),
  ( 'lesen', 'a1', 'texts-reading', 'ru', 'advice', true,
    'Объявления и короткие тексты: как не запутаться в формате',
    'Lesen Teil 2 на A1 — это объявления, расписания, меню. Логика чтения отличается от связного текста.',
    $body${"why":"Lesen Teil 2 на A1 — самая необычная для русскоязычных кандидатов часть. Это не связный текст, а структурированные объявления: расписание поездов, меню кафе, объявления в магазине. Подход к ним — другой: читать нужно не сверху вниз, а сразу искать категорию, в которой ответ. Без этого навыка время уходит впустую.","steps":["Сначала бегло посмотрите на структуру: где даты, где цены, где имена, где описания. Не читайте — просто оцените макет.","Прочитайте вопрос — определите, в какой категории текста ответ. Если вопрос про время — смотрите на колонку с временами.","Сразу переходите к нужной категории, игнорируя остальное. На объявлении про распродажу не нужно читать всё про скидки — найдите конкретный товар из вопроса.","Если текст содержит сокращения (z.B., usw., ggf.) — выучите их заранее, на экзамене расшифровывать некогда."],"drill":"Найдите любое немецкое расписание (поездов, мероприятий) или меню. За 30 секунд найдите ответы на 3 вопроса: «Когда X?», «Сколько стоит Y?», «Где Z?». Без чтения всего текста.","avoid":"Не читайте объявления как связный текст слева направо — теряете время и путаетесь в структуре. Меню или расписание — это таблица, а не книга.","progress":"После 10 тренировочных Teil 2 вы автоматически сканируете структуру и находите ответы за 30-60 секунд на текст."}$body$::jsonb ),
  ( 'horen', 'a1', 'audio-listening', 'ru', 'advice', true,
    'Как улучшить понимание чисел и времени на слух',
    'Числа на немецком сложны для русского уха — единицы и десятки переставлены. Это тренируется отдельно.',
    $body${"why":"В Hören A1 числа и время — самая частая категория вопросов: «Сколько стоит?», «Во сколько встреча?», «Какой номер?». Немецкие числа сложны тем, что единицы говорятся ПЕРЕД десятками: 21 — «einundzwanzig» (один-и-двадцать), 47 — «siebenundvierzig» (семь-и-сорок). Русский мозг автоматически слышит «один» и хочет записать «1», а реальное число — «21».","steps":["Каждый день 5 минут — диктант чисел. Включайте YouTube-видео «Zahlen auf Deutsch» (любое), записывайте числа в тетрадь, проверяйте.","Тренируйте именно проблемные числа от 21 до 99: einundzwanzig, zweiunddreißig, dreiundvierzig… Запишите 20 разных, прослушайте, запишите цифрами.","Время на немецком: «halb sieben» = 6:30 (половина седьмого, не половина шестого!), «Viertel nach sieben» = 7:15, «Viertel vor acht» = 7:45.","Цены: «zwei Euro fünfzig» = 2,50 €. Запятая в немецком — это десятичный разделитель."],"drill":"Прямо сейчас послушайте 5 раз: «Es kostet siebenundvierzig Euro neunzig». Запишите цифрами. Правильный ответ: 47,90 €. Повторите с другими числами — пока не начнёте уверенно понимать.","avoid":"Не пытайтесь «перевести» немецкое число в русское в уме — потеряете секунду и пропустите следующую информацию. Тренируйте до автоматического понимания на немецком.","progress":"Через 2 недели ежедневных диктантов вы понимаете цены и время в аудио без задержки на «расшифровку»."}$body$::jsonb ),
  ( 'sprechen', 'a1', 'general', 'ru', 'advice', true,
    'План подготовки к A1 за 4 недели до экзамена',
    'Если до экзамена месяц — фокус только на проверенных слабых зонах, не пытайтесь учить всё.',
    $body${"why":"За 4 недели до экзамена A1 нет времени на «изучение немецкого с нуля». Если вы здесь — у вас уже есть база, но есть пробелы. Главная ошибка — пытаться выучить «все правила». Правильная стратегия — определить 3-5 слабых зон по результатам тренировочных тестов и работать только с ними.","steps":["Неделя 1: пройдите 2 полных Modellsatz Goethe A1. Не для оценки, а для диагностики — где конкретно теряете баллы (Hören? Schreiben? Какие именно задания?).","Неделя 2-3: 80% времени — на 3 худших слабых зоны. По каждой — отдельный план: упражнения, повторения, тренировочные задания.","Неделя 4: пройдите ещё 1-2 Modellsatz уже на оценку. Сравните с первой неделей — где улучшение, где нет.","Последние 3 дня: не учите ничего нового. Повторяйте уже выученное, спите 8+ часов, готовьте документы и место экзамена."],"drill":"Прямо сейчас составьте честный список: какие 3 модуля/задания у вас худшие? Если не знаете — пройдите один Modellsatz сегодня и составьте список завтра.","avoid":"Не пытайтесь «выучить всё подряд» из учебника — за 4 недели не получится, а слабые зоны останутся. Точечная работа эффективнее.","progress":"Через 4 недели по результатам Modellsatz вы стабильно набираете 70%+ правильных ответов в каждом модуле."}$body$::jsonb ),
